import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Profile.css";

export default function Profile() {
  const navigate = useNavigate();

  const [editing, setEditing] = useState(false);

  const role = localStorage.getItem("role") || "student";
  const [name, setName] = useState(localStorage.getItem("userName") || "");
  const [email, setEmail] = useState(localStorage.getItem("email") || "");
  const [roll, setRoll] = useState(localStorage.getItem("rollNumber") || "");
  const [phone, setPhone] = useState(localStorage.getItem("phone") || "");
  const [year, setYear] = useState(localStorage.getItem("year") || "");
  const [semester, setSemester] = useState(localStorage.getItem("semester") || "");
  const [designation, setDesignation] = useState(localStorage.getItem("designation") || "");

  const [profilePic, setProfilePic] = useState(localStorage.getItem("profilePic") || "");

  function handleSave() {
    localStorage.setItem("userName", name);
    localStorage.setItem("email", email);
    localStorage.setItem("rollNumber", roll);
    localStorage.setItem("phone", phone);

    if (role === "student") {
      localStorage.setItem("year", year);
      localStorage.setItem("semester", semester);
    } else {
      localStorage.setItem("designation", designation);
    }

    if (profilePic) {
      localStorage.setItem("profilePic", profilePic);
    }

    alert("Profile updated successfully!");
    setEditing(false);
  }

  function handleProfilePicChange(e) {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setProfilePic(reader.result);
      };
      reader.readAsDataURL(file);
    }
  }

  function handleLogout() {
    localStorage.clear();
    navigate("/login");
  }

  return (
    <div className="profile-container">
      <h1>👤 My Profile</h1>

      <div className="profile-pic">
        {profilePic ? (
          <img src={profilePic} alt="Profile" />
        ) : (
          <div className="placeholder-pic">Add Photo</div>
        )}
        {editing && <input type="file" accept="image/*" onChange={handleProfilePicChange} />}
      </div>

      <div className="profile-fields">
        <p><strong>Role:</strong> {role}</p>

        {editing ? (
          <>
            <label>Name:</label>
            <input value={name} onChange={(e) => setName(e.target.value)} />

            {role === "student" && (
              <>
                <label>Roll Number:</label>
                <input value={roll} onChange={(e) => setRoll(e.target.value)} />
              </>
            )}

            <label>Email:</label>
            <input value={email} onChange={(e) => setEmail(e.target.value)} />

            <label>Phone:</label>
            <input value={phone} onChange={(e) => setPhone(e.target.value)} />

            {role === "student" && (
              <>
                <label>Year:</label>
                <input value={year} onChange={(e) => setYear(e.target.value)} />

                <label>Semester:</label>
                <input value={semester} onChange={(e) => setSemester(e.target.value)} />
              </>
            )}

            {(role === "admin" || role === "hr") && (
              <>
                <label>Designation:</label>
                <input value={designation} onChange={(e) => setDesignation(e.target.value)} />
              </>
            )}

            <button onClick={handleSave}>Save</button>
          </>
        ) : (
          <>
            <p><strong>Name:</strong> {name}</p>
            {role === "student" && <p><strong>Roll Number:</strong> {roll}</p>}
            <p><strong>Email:</strong> {email}</p>
            <p><strong>Phone:</strong> {phone}</p>
            {role === "student" && (
              <>
                <p><strong>Year:</strong> {year}</p>
                <p><strong>Semester:</strong> {semester}</p>
              </>
            )}
            {(role === "admin" || role === "hr") && (
              <p><strong>Designation:</strong> {designation}</p>
            )}
          </>
        )}
      </div>

      <button className="edit-btn" onClick={() => setEditing(!editing)}>
        {editing ? "Cancel" : "Edit Profile"}
      </button>

      <button className="logout-btn" onClick={handleLogout}>Logout</button>
    </div>
  );
}
